class Solution {
public:
    int shortestMatchingSubstring(string s, string p) {
        int n = s.size(), m = p.size();
        int idx1 = -1, idx2 = -1;
        for (int i = 0; i < n; i++) {
            if (p[0] == '*' || s[i] == p[0]) idx1 = i;
            if (p[m - 1] == '*' || s[i] == p[m - 1]) idx2 = i;
            if (idx1 != -1 && idx2 != -1) {
                int j = 0, k = 0;
                while (j < m && k < n) {
                    if (p[j] == '*' || s[k] == p[j]) {
                        j++;
                        k++;
                    } else if (p[j] == '*') {
                        j++;
                    } else if (s[k] == p[j]) {
                        j++;
                        k++;
                    } else {
                        break;
                    }
                }
                if (j == m) {
                    return i - idx1 + 1;
                }
            }
        }
        return -1;
    }
};
```

